<template><view class="page"><view class="head"><text @tap="back">‹</text><view><text class="head-title">申请加盟</text><text class="head-subtitle">申请成为区域代理</text></view></view><view class="card"><text class="tip">提交后会进入后台“区域代理审核”，审核通过后该区域将开通同城配送与厨师代炒。</text><input v-model="form.applicantName" placeholder="申请人姓名"/><input v-model="form.phone" type="number" maxlength="11" placeholder="联系电话"/><view class="line"><input v-model="form.province" placeholder="省"/><input v-model="form.city" placeholder="市"/><input v-model="form.district" placeholder="区/县"/></view><input v-model="form.address" placeholder="详细地址"/><textarea v-model="form.experience" maxlength="300" placeholder="相关经验、资源或申请说明"></textarea><view class="submit" :class="{disabled:loading}" @tap="submit">提交审核</view></view></view></template>
<script>import{apiRegionApply}from'@/api/region.js';import{ensureLogin}from'@/utils/login.js';export default{data(){return{loading:false,form:{applicantName:'',phone:'',province:'',city:'',district:'',address:'',experience:''}}},methods:{async submit(){let f=this.form;if(this.loading)return;if(!f.applicantName.trim()||!/^1\d{10}$/.test(f.phone)||!f.province.trim()||!f.city.trim()||!f.district.trim()){uni.showToast({title:'请完整填写姓名、手机号和区域',icon:'none'});return}try{this.loading=true;await ensureLogin();await apiRegionApply(f);uni.setStorageSync('currentRegion',{province:f.province,city:f.city,district:f.district,address:f.address});uni.showToast({title:'申请已提交',icon:'success'});setTimeout(()=>this.back(),900)}catch(e){}finally{this.loading=false}},back(){uni.navigateBack()}}}</script>
<style>.page{min-height:100vh;background:#f5faf8;color:#202725}.head{height:170rpx;padding:calc(34rpx + env(safe-area-inset-top)) 28rpx 22rpx;display:flex;align-items:flex-end;background:linear-gradient(135deg,#dbfaf1,#f8fffc);box-sizing:border-box}.head>text{width:66rpx;font-size:56rpx}.head view{display:flex;flex-direction:column}.head-title{font-size:37rpx;font-weight:700}.head-subtitle{margin-top:5rpx;color:#819089;font-size:22rpx}.card{margin:24rpx;padding:28rpx;border-radius:25rpx;background:#fff}.tip{display:block;margin-bottom:24rpx;padding:20rpx;border-radius:14rpx;background:#edfaf6;color:#668078;font-size:23rpx;line-height:1.55}.card input{height:80rpx;margin-bottom:16rpx;padding:0 20rpx;border-radius:15rpx;background:#f4f7f6;box-sizing:border-box}.line{display:flex;gap:12rpx}.line input{flex:1;min-width:0}.card textarea{width:100%;height:180rpx;padding:20rpx;border-radius:15rpx;background:#f4f7f6;box-sizing:border-box}.submit{height:82rpx;margin-top:24rpx;border-radius:42rpx;background:#35cda4;color:#fff;display:flex;align-items:center;justify-content:center;font-size:30rpx;font-weight:900}.disabled{opacity:.55}</style>
